CREATE TABLE IF NOT EXISTS currencies ( id Integer not null, serial_id VARCHAR(50) UNIQUE NOT NULL, code VARCHAR(50) UNIQUE NOT NULL, name VARCHAR(50) UNIQUE NOT NULL, symbol VARCHAR(3), active boolean DEFAULT true, CONSTRAINT app_currencies_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS currency_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY currencies.id;
INSERT INTO currencies (id, serial_id, code, name, symbol, active) VALUES (nextval('currency_id_seq'), 'CU001','EGP', 'جنيه مصرى', 'E£', true), (nextval('currency_id_seq'), 'CU002', 'USD', 'US Dollar', '$', true), (nextval('currency_id_seq'), 'CU003', 'EUR', 'Euro', '€', true), (nextval('currency_id_seq'), 'CU004', 'GBP', 'British Pound', '£', true), (nextval('currency_id_seq'), 'CU005', 'INR', 'Indian Rupee', '₹', true), (nextval('currency_id_seq'), 'CU006', 'AUD', 'Australian Dollar', 'A$', true), (nextval('currency_id_seq'), 'CU007', 'CAD', 'Canadian Dollar', 'C$', true), (nextval('currency_id_seq'), 'CU008', 'CHF', 'Swiss Franc', 'CHF', false), (nextval('currency_id_seq'), 'CU009', 'CNY', 'Chinese Yuan', '¥', true), (nextval('currency_id_seq'), 'CU010', 'BRL', 'Brazilian Real', 'R$', false), (nextval('currency_id_seq'), 'CU011', 'JPY', 'Japanese Yen', '¥', true);
CREATE TABLE IF NOT EXISTS exchange_rates ( id bigint not null, serial_id VARCHAR(50) UNIQUE NOT NULL, valid_from timestamp(6) without time zone NOT NULL, rate DECIMAL(15,2) NOT NULL, currency_id Integer NOT NULL, CONSTRAINT exchange_rates_p_key PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS exchange_rate_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY exchange_rates.id;
CREATE TABLE IF NOT EXISTS account_currency ( account_id BIGINT NOT NULL, currency_id integer NOT NULL, CONSTRAINT account_currency_p_key PRIMARY KEY (account_id, currency_id), CONSTRAINT fk_account_currency FOREIGN KEY (account_id) REFERENCES app_accounts (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT fk_currency_account FOREIGN KEY (currency_id) REFERENCES currencies (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION );
INSERT INTO account_currency( account_id, currency_id) VALUES (1, 1);
